DOMAIN_SUMMARY = "Cybersecurity Evidence Review involves analyzing diverse digital artifacts (e.g., incident reports, log files, vulnerability scans, policy documents) to understand security incidents, assess compliance, or identify threats. This project simplifies that process by allowing a user to 'chat' with their evidence base, retrieving relevant sections and generating concise answers to specific questions, reducing manual document review time."
USER_PERSONA = 'Junior Cybersecurity Analyst: A new analyst or security intern who needs to quickly get up to speed on an incident, understand a specific vulnerability, or find information within a large set of incident-related documents without having to manually read through every file.'
STARTER_QUESTIONS = ['What was the root cause identified in the incident report?', 'List all affected systems mentioned in the network logs.', "What steps are required for data breach notification according to the 'Incident Response Policy.pdf'?", 'Are there any indicators of compromise (IOCs) listed in the latest threat intelligence report?', "Summarize the findings of the vulnerability scan for server 'SRV-WEB-01'."]
WORKFLOW_STEPS = ['**1. Document Preparation:** User gathers cybersecurity evidence documents (e.g., incident reports, log files, policy docs).', '**2. Document Upload:** User navigates to the web UI and uploads one or more documents via the designated upload area.', '**3. Ingestion & Embedding:** The backend service receives the document, extracts text, splits it into smaller chunks, generates vector embeddings for each chunk, and stores these embeddings along with their original text in ChromaDB.', "**4. Document Listing:** The uploaded document appears in the 'Uploaded Documents' list on the UI, confirming successful ingestion.", "**5. Query Formulation:** User types a natural language question into the chat interface related to the uploaded documents (e.g., 'What was the timeline of the attack?').", "**6. Retrieval:** The backend embeds the user's query and performs a similarity search in ChromaDB to retrieve the most relevant document chunks.", "**7. Context Augmentation:** The retrieved chunks are combined with the user's original query into a coherent prompt for the LLM.", '**8. Generation:** The LLM processes the augmented prompt and generates a concise, relevant answer based solely on the provided context.']
BUSINESS_RULES = ['Documents must be less than 10MB to ensure efficient processing for a beginner setup.', 'Only text-based documents (or those convertible to text like PDF) are supported.', 'Document chunks must have a minimum length to ensure semantic meaning (e.g., 50 characters).', 'The RAG system must only answer questions based on the content of the uploaded documents; no external knowledge.', 'The system should prioritize factual extraction and summarization over creative generation.', 'Maximum of 5 relevant chunks will be retrieved for context augmentation to manage LLM token limits.', 'A clear error message must be displayed if no relevant information is found for a query.']
TOOL_CATALOG = [{'name': 'vectorstoresearch', 'description': "Searches the ChromaDB vector store for document chunks semantically similar to the user's query and retrieves their original text content. This is the primary tool for fetching relevant context."}, {'name': 'documentembedder', 'description': 'Generates numerical vector representations (embeddings) for text segments using a pre-trained Sentence Transformer model.'}, {'name': 'textchunker', 'description': 'Splits long text documents into smaller, manageable chunks suitable for embedding and LLM context windows, while maintaining some contextual overlap.'}]
